	@Test
	void physicalJoinCostUsesDeliveredChildBindingProfiles() {
		CascadesCostModel model = CascadesCostModel.from(new EvaluationStatistics());
		Join join = new Join(pattern("s", "p1", "o"), pattern("o", "p2", "x"));
		MemoExpr physicalJoin = new MemoExpr(10, 0, "Join", List.of(1, 2), "test", join,
				PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), "join-test");
		Winner left = profileWinner(1, join.getLeftArg(), finiteProfile("o", iri("urn:test:o1")));
		Winner matchingRight = profileWinner(2, join.getRightArg(), finiteProfile("o", iri("urn:test:o1")));
		Winner disjointRight = profileWinner(3, join.getRightArg(), finiteProfile("o", iri("urn:test:o2")));

		CostVector matching = model.localCost(physicalJoin, OptimizationGoal.root(), List.of(left, matchingRight));
		CostVector disjoint = model.localCost(physicalJoin, OptimizationGoal.root(), List.of(left, disjointRight));

		assertEquals(1.0d, matching.rows(), 0.0d);
		assertEquals(0.0d, disjoint.rows(), 0.0d,
				"Parent costing must use child finite anchors retained in delivered binding profiles");
	}

	@Test
	void physicalJoinCostCarriesJoinedSketchProfileAcrossWinnerBoundary() {
		CascadesCostModel model = CascadesCostModel.from(new EvaluationStatistics());
		Join join = new Join(pattern("s", "p1", "o"), pattern("o", "p2", "x"));
		MemoExpr physicalJoin = new MemoExpr(10, 0, "Join", List.of(1, 2), "test", join,
				PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), "join-test");
		DistributionSketch leftSketch = new TestSketch(40.0d, 17.0d);
		DistributionSketch rightSketch = new TestSketch(30.0d, 17.0d);
		Winner left = sketchedProfileWinner(1, join.getLeftArg(), "o", 100.0d, leftSketch);
		Winner right = sketchedProfileWinner(2, join.getRightArg(), "o", 80.0d, rightSketch);

		CostVector cost = model.localCost(physicalJoin, OptimizationGoal.root(), List.of(left, right));
		PhysicalProperties delivered = model.deliveredProperties(physicalJoin, OptimizationGoal.root(),
				List.of(left, right));
		DistributionSketch joinedSketch = delivered.bindingProfile().variables().get("o").sketch();

		assertEquals(17.0d, cost.rows(), 0.0d,
				"Parent physical costing must consume child sketch profiles instead of rows-only heuristic bags");
		assertNotNull(joinedSketch,
				"A physical winner should deliver the joined sketch profile to its parent winner boundary");
		assertNotSame(leftSketch, joinedSketch, "The delivered joined sketch must not be stale left input evidence");
		assertNotSame(rightSketch, joinedSketch, "The delivered joined sketch must not be stale right input evidence");
	}

	@Test
	void parentJoinUsesRichChildEstimateFromWinnerDeliveredProfile() {
		CascadesCostModel warmModel = CascadesCostModel.from(new EvaluationStatistics());
		Join childJoin = new Join(pattern("s", "p1", "x"), pattern("x", "p2", "y"));
		MemoExpr childExpr = new MemoExpr(20, 0, "Join", List.of(1, 2), "test", childJoin,
				PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), "child-join");
		Winner childLeft = sketchedProfileWinner(1, childJoin.getLeftArg(), "x", 100.0d,
				new TestSketch(60.0d, 17.0d));
		Winner childRight = sketchedProfileWinner(2, childJoin.getRightArg(), "y", 100.0d,
				new TestSketch(7.0d, 17.0d));
		CostVector childCost = warmModel.localCost(childExpr, OptimizationGoal.root(),
				List.of(childLeft, childRight));
		PhysicalProperties childDelivered = warmModel.deliveredProperties(childExpr, OptimizationGoal.root(),
				List.of(childLeft, childRight));

		Join parentJoin = new Join(childJoin, pattern("y", "p3", "z"));
		MemoExpr parentExpr = new MemoExpr(30, 0, "Join", List.of(20, 3), "test", parentJoin,
				PhysicalProperties.ANY, RuleKind.IMPLEMENTATION, CostVector.ZERO, List.of(), "parent-join");
		Winner profiledChildWinner = new Winner(childExpr, childJoin, childDelivered, childCost, List.of(), false, "");
		Winner rightWinner = winner(3, parentJoin.getRightArg(), 50.0d);

		CostVector warm = warmModel.localCost(parentExpr, OptimizationGoal.root(),
				List.of(profiledChildWinner, rightWinner));
		CascadesCostModel coldModel = CascadesCostModel.from(new EvaluationStatistics());
		CostVector cold = coldModel.localCost(parentExpr, OptimizationGoal.root(),
				List.of(profiledChildWinner, rightWinner));

		assertEquals(cold.rows(), warm.rows(), 0.0d,
				"Parent costing must be a pure function of the selected Winner, not prior model-local cache entries");
		assertNotEquals(50.0d, warm.rows(),
				"The Winner-delivered profile must preserve child distinct/sketch evidence beyond scalar rows");
	}

