		JoinFactorCostModel noCompositeEstimate = (factor, boundVars) -> Optional.empty();
		CascadesCostModel model = model(RdfStatisticsProvider.EMPTY, noCompositeEstimate);
		StatementPattern left = pattern("entity", "type", "kind");
